import json

# Get the voice call data from the stored variable
voice_call_data = locals()['var_functions.query_db:0']

# Extract the transcript body from the first result
if voice_call_data and len(voice_call_data) > 0:
    transcript = voice_call_data[0].get('Body__c', '')
else:
    transcript = ''

# Initialize BANT factors
budget_met = False
authority_met = False
need_met = False
timeline_met = False

# Analyze for Budget
if '$2,261' in transcript and '$2,000' in transcript and 'budget' in transcript.lower():
    budget_met = True

# Analyze for Authority - Ali indicates he needs to consult with finance team
if "final say" in transcript or "consult with" in transcript or "finance team" in transcript:
    authority_met = False
else:
    authority_met = True

# Analyze for Need
if "simulation capabilities" in transcript and "PulseSim Pro" in transcript:
    need_met = True

# Analyze for Timeline
if "tight timeline" in transcript or "installation" in transcript:
    if "within a day" in transcript or "one day" in transcript:
        timeline_met = True

# Check if authority is not met (this is the main issue)
failed_factors = []

if not budget_met:
    failed_factors.append("Budget")
if not authority_met:
    failed_factors.append("Authority")
if not need_met:
    failed_factors.append("Need")
if not timeline_met:
    failed_factors.append("Timeline")

print("__RESULT__:")
print(json.dumps(failed_factors))

